<div class="d-flex justify-content-between align-items-center mb-4"><h1 class="h3">Today's Jobs</h1><span class="badge text-bg-primary"><?=array_sum(array_map('count',$groupedJobs))?> jobs</span></div><?php if(!$groupedJobs):?><div class="alert alert-light border">No jobs assigned today.</div><?php endif?><?php foreach($groupedJobs as $crewName=>$jobs):?><section class="mb-4"><div class="d-flex align-items-center gap-2 mb-2"><i class="fa-solid fa-people-group text-primary"></i><h2 class="h5 mb-0"><?=e($crewName)?></h2><span class="badge text-bg-light"><?=count($jobs)?></span></div><div class="row g-3"><?php foreach($jobs as $j):?><div class="col-12"><div class="card card-body"><div class="d-flex justify-content-between gap-3"><div><div class="text-muted"><?=e($j['scheduled_start']?date('g:i A',strtotime($j['scheduled_start'])):'Unscheduled')?></div><h3 class="h5 mb-1"><?=e($j['display_name'])?></h3><p class="mb-1"><?=e($j['service_summary'])?></p><small><?=e(trim(($j['address1']??'').' '.($j['city']??'').' '.($j['state']??'').' '.($j['postal_code']??'')))?></small></div><div class="text-end"><span class="badge text-bg-secondary mb-2"><?=e($j['status'])?></span><br><a class="btn btn-primary" href="/portal/jobs/<?=$j['id']?>">Open Job</a></div></div></div></div><?php endforeach?></div></section><?php endforeach?>
